import React from 'react';

const Certificates = () => {
  const certificates = [
    { title: 'React Certification', issuer: 'Coursera', date: '2023' },
    { title: 'JavaScript Advanced', issuer: 'Udemy', date: '2022' },
  ];

  return (
    <section id="certificates" className="certificates-section py-5">
      <div className="container">
        <h2 className="text-center mb-4">Certificates</h2>
        <div className="row">
          {certificates.map((cert, index) => (
            <div key={index} className="col-md-6 mb-3">
              <div className="card">
                <div className="card-body">
                  <h5 className="card-title">{cert.title}</h5>
                  <p className="card-text">Issued by: {cert.issuer}</p>
                  <p className="card-text">Date: {cert.date}</p>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Certificates;
